sql:
SELECT activity_name, activity_description
FROM fitness_activities
ORDER BY calorie_burn_rate DESC;

external_knowledge:
- 'finished' simulations refer to those with a status labeled as 'completed';
- 'specifics of their simulations' include the simulation name, start date, end date, status, predicted fitness score, and simulated fitness score;
- 'participants' are referred to by their user names from the 'users' table;
- 'models they used' are the names of the fitness models from the 'fitness_models' table.

sql:
SELECT activity_name, calorie_burn_rate
FROM fitness_activities
WHERE calorie_burn_rate = (
    SELECT MAX(calorie_burn_rate)
    FROM fitness_activities
);

SELECT model_name, description
FROM fitness_models
WHERE model_type = 'machine learning';
